//! Mint a Corey license for a buyer.
//!
//! Reads the private key generated by `license_keygen`, signs a
//! payload describing the buyer + expiry, and prints the resulting
//! token. You hand-deliver this token to the buyer (email / IM /
//! whatever) and they paste it into Corey's "Activate" dialog.
//!
//! ```bash
//! cargo run --bin mint_license -- \
//!     --key ~/.corey-license/private.pem \
//!     --user alice@example.com \
//!     --expires 2027-04-27
//!
//! # → COREY-LICENSE/v1
//! # eyJ1c2VyIjoiYWxpY2VAZXhhbXBsZS5jb20iLCJpc3N1ZWQiOiIyMDI2L…
//! ```
//!
//! Flags:
//!   --key <path>        Private key PEM (default: ~/.corey-license/private.pem)
//!   --user <id>         Buyer identifier (email / name / org slug). Required.
//!   --expires <date>    YYYY-MM-DD or RFC-3339 datetime. Omit for perpetual.
//!   --features <a,b,c>  Comma-separated capability tags. Optional.
//!
//! Tokens are valid forever (signature-wise) — only `--expires` ties
//! them to time. There's no built-in revocation list; if you need
//! to invalidate a key, rotate the keypair and re-issue everyone.
//! For a small audience that's tolerable; if it isn't, you've
//! outgrown this scheme — switch to a SaaS license server.

use std::fs;
use std::path::PathBuf;

use base64::engine::general_purpose::URL_SAFE_NO_PAD;
use base64::Engine;
use ed25519_dalek::pkcs8::DecodePrivateKey;
use ed25519_dalek::{Signer, SigningKey};
use serde::Serialize;

#[derive(Serialize)]
struct Payload {
    user: String,
    issued: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    expires: Option<String>,
    #[serde(skip_serializing_if = "Vec::is_empty")]
    features: Vec<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    machine_id: Option<String>,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut key_path: Option<PathBuf> = None;
    let mut user: Option<String> = None;
    let mut expires: Option<String> = None;
    let mut features: Vec<String> = Vec::new();
    let mut machine_id: Option<String> = None;

    let mut args = std::env::args().skip(1).collect::<Vec<_>>().into_iter();
    while let Some(flag) = args.next() {
        match flag.as_str() {
            "--key" => key_path = args.next().map(PathBuf::from),
            "--user" => user = args.next(),
            "--expires" => expires = args.next(),
            "--features" => {
                features = args
                    .next()
                    .unwrap_or_default()
                    .split(',')
                    .map(|s| s.trim().to_string())
                    .filter(|s| !s.is_empty())
                    .collect();
            }
            "--machine-id" => {
                // The buyer reads this from Settings → License (or the
                // pre-activation gate) and forwards it to you. We do
                // a sanity-check on length only — the verifier just
                // does string equality, so any non-empty value works.
                machine_id = args
                    .next()
                    .map(|s| s.trim().to_string())
                    .filter(|s| !s.is_empty());
            }
            "-h" | "--help" => {
                println!("{}", include_str!("mint_license_help.txt"));
                return Ok(());
            }
            other => return Err(format!("unknown flag {other}").into()),
        }
    }

    let user = user.ok_or("missing --user. e.g. --user alice@example.com")?;
    let key_path = key_path
        .or_else(default_key_path)
        .ok_or("could not resolve default --key path; pass --key explicitly")?;

    let pem =
        fs::read_to_string(&key_path).map_err(|e| format!("read {}: {e}", key_path.display()))?;
    let signing = SigningKey::from_pkcs8_pem(&pem)
        .map_err(|e| format!("parse {} as PKCS8 ed25519 PEM: {e}", key_path.display()))?;

    let issued = chrono::Utc::now().format("%Y-%m-%dT%H:%M:%SZ").to_string();
    let payload = Payload {
        user,
        issued,
        expires,
        features,
        machine_id,
    };
    let payload_bytes = serde_json::to_vec(&payload)?;
    let sig = signing.sign(&payload_bytes);
    let token = format!(
        "{}.{}",
        URL_SAFE_NO_PAD.encode(&payload_bytes),
        URL_SAFE_NO_PAD.encode(sig.to_bytes()),
    );

    println!("{token}");
    Ok(())
}

fn default_key_path() -> Option<PathBuf> {
    let home = std::env::var_os("HOME").or_else(|| std::env::var_os("USERPROFILE"))?;
    Some(
        PathBuf::from(home)
            .join(".corey-license")
            .join("private.pem"),
    )
}
